#include <bits/stdc++.h>
using namespace std;
int n,w,c[20],sum[20],ans=100;
bool cmp(int x,int y){
    return x>y;
}
void dfs(int step,int num){
    if(num>=ans)return;
    if(step==n+1){
        ans=num;
        return;
    }
    sum[num+1]=c[step];
    dfs(step+1,num+1);
    for(int i=1;i<=num;i++){
        if(sum[i]+c[step]<=w){
            sum[i]+=c[step];
            dfs(step+1,num);
            sum[i]-=c[step];
        }
    }
}

int main(){
    cin>>n>>w;
    for(int i=1;i<=n;i++)cin>>c[i];
    sort(c+1,c+n+1,cmp);
    dfs(1,0);
    cout<<ans;
    return 0;
}
